// // This is a 4-bit subtractor module that computes the difference between two 4-bit input numbers (a and b) along with a borrow-in input (bi). The module outputs a 4-bit difference and a borrow-out signal (bo), handling underflow from the subtraction of the two inputs and the borrow-in.
module top_module(sum, co, a, b, ci);output	[3:0]sum;
	output	co;
	input	[3:0]a,b;
	input	ci;

	assign	{co,sum}	=a+b+ci;
endmodule
